import{_ as e,o as d,c as o,a2 as c}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"控制效果","description":"","frontmatter":{},"headers":[],"relativePath":"guide/effects-control.md","filePath":"guide/effects-control.md","lastUpdated":1781103706000}'),a={name:"guide/effects-control.md"};function r(i,t,n,s,l,h){return d(),o("div",null,[...t[0]||(t[0]=[c('<h1 id="控制效果" tabindex="-1">控制效果 <a class="header-anchor" href="#控制效果" aria-label="Permalink to &quot;控制效果&quot;">​</a></h1><p>控制效果由 <code>EffectType</code> 定义，框架通过 <code>SkillSet.GetCharacterStateByEffectType()</code> 映射到角色状态。</p><h2 id="强控制效果-改变角色状态" tabindex="-1">强控制效果（改变角色状态） <a class="header-anchor" href="#强控制效果-改变角色状态" aria-label="Permalink to &quot;强控制效果（改变角色状态）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>EffectType</th><th>映射的 CharacterState</th><th>说明</th></tr></thead><tbody><tr><td><code>Stun</code></td><td><code>NotActionable</code></td><td>眩晕 → 完全行动不能</td></tr><tr><td><code>Freeze</code></td><td><code>NotActionable</code></td><td>冻结 → 完全行动不能</td></tr><tr><td><code>Sleep</code></td><td><code>NotActionable</code></td><td>睡眠 → 完全行动不能</td></tr><tr><td><code>Knockdown</code></td><td><code>NotActionable</code></td><td>击倒 → 完全行动不能</td></tr><tr><td><code>Petrify</code></td><td><code>NotActionable</code></td><td>石化 → 完全行动不能</td></tr><tr><td><code>Banish</code></td><td><code>NotActionable</code></td><td>放逐 → 完全行动不能</td></tr><tr><td><code>Root</code></td><td><code>ActionRestricted</code></td><td>定身 → 行动受限</td></tr><tr><td><code>Fear</code></td><td><code>ActionRestricted</code></td><td>恐惧 → 行动受限</td></tr><tr><td><code>Taunt</code></td><td><code>ActionRestricted</code></td><td>嘲讽 → 行动受限</td></tr><tr><td><code>Charm</code></td><td><code>ActionRestricted</code></td><td>魅惑 → 行动受限</td></tr><tr><td><code>Confusion</code></td><td><code>ActionRestricted</code></td><td>混乱 → 行动受限</td></tr><tr><td><code>Silence</code></td><td><code>SkillRestricted</code></td><td>沉默 → 技能受限</td></tr><tr><td><code>SilenceMagic</code></td><td><code>SkillRestricted</code></td><td>法术沉默 → 技能受限</td></tr><tr><td><code>Disarm</code></td><td><code>AttackRestricted</code></td><td>缴械 → 攻击受限</td></tr></tbody></table><h2 id="软控制效果-不改变角色状态" tabindex="-1">软控制效果（不改变角色状态） <a class="header-anchor" href="#软控制效果-不改变角色状态" aria-label="Permalink to &quot;软控制效果（不改变角色状态）&quot;">​</a></h2><p>以下 EffectType 属于负面效果但不改变 <code>CharacterState</code>：</p><p><code>Slow</code>、<code>Weaken</code>、<code>Poison</code>、<code>Burn</code>、<code>Bleed</code>、<code>Blind</code>、<code>Cripple</code>、<code>Curse</code>、<code>Exhaustion</code>、<code>ManaBurn</code>、<code>GrievousWound</code>、<code>Vulnerable</code>、<code>Delay</code>、<code>PenetrationBoost</code>（对敌方）、<code>MagicResistBreak</code></p><h2 id="状态覆盖优先级回顾" tabindex="-1">状态覆盖优先级回顾 <a class="header-anchor" href="#状态覆盖优先级回顾" aria-label="Permalink to &quot;状态覆盖优先级回顾&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NotActionable → ActionRestricted → BattleRestricted → SkillRestricted / AttackRestricted → Actionable</span></span></code></pre></div><p>当角色同时受多种控制时，最高级别的状态生效。</p><h2 id="豁免类型" tabindex="-1">豁免类型 <a class="header-anchor" href="#豁免类型" aria-label="Permalink to &quot;豁免类型&quot;">​</a></h2><p>每个控制效果都有对应的豁免属性（核心属性），由 <code>SkillSet.GetExemptionTypeByEffectType()</code> 确定：</p><table tabindex="0"><thead><tr><th>豁免属性</th><th>可豁免的控制效果</th></tr></thead><tbody><tr><td><strong>力量 (STR)</strong></td><td>眩晕、冻结、击倒、嘲讽、定身、缴械、石化、重伤</td></tr><tr><td><strong>敏捷 (AGI)</strong></td><td>睡眠、恐惧、减速、致盲、致残、燃烧、流血、迟滞</td></tr><tr><td><strong>智力 (INT)</strong></td><td>沉默、法术沉默、魅惑、混乱、放逐、打断施法、诅咒、疲劳、魔力燃烧、易伤</td></tr></tbody></table>',13)])])}const f=e(a,[["render",r]]);export{b as __pageData,f as default};
